import{_ as t,o as r,c as a,a7 as s}from"./chunks/framework.C5fSpjcB.js";const y=JSON.parse('{"title":"Key Orders","description":"","frontmatter":{},"headers":[],"relativePath":"en/key-orders/index.md","filePath":"en/key-orders/index.md","lastUpdated":1775394001000}'),o={name:"en/key-orders/index.md"};function i(d,e,l,n,h,c){return r(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="key-orders" tabindex="-1">Key Orders <a class="header-anchor" href="#key-orders" aria-label="Permalink to &quot;Key Orders&quot;">​</a></h1><p><strong>Key Orders</strong> (钥令) are powerful abilities activated by spending <strong>1000 Silver Key</strong> energy during combat. They serve as a secondary ultimate ability system alongside Madness Burst.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspect</th><th>Detail</th></tr></thead><tbody><tr><td>Activation Cost</td><td>1000 Silver Key</td></tr><tr><td>Trigger</td><td>Manual activation when Silver Key is full</td></tr><tr><td>Source</td><td>Gacha, events, progression rewards</td></tr><tr><td>Effect</td><td>Varies by Key Order equipped</td></tr></tbody></table><h2 id="how-key-orders-work" tabindex="-1">How Key Orders Work <a class="header-anchor" href="#how-key-orders-work" aria-label="Permalink to &quot;How Key Orders Work&quot;">​</a></h2><ol><li><strong>Silver Key accumulates</strong> during battle through playing cards, taking damage, and realm-specific effects.</li><li>When Silver Key reaches <strong>1000</strong>, the Key Order becomes available.</li><li><strong>Activate manually</strong> to trigger the equipped Key Order&#39;s effect.</li><li>Silver Key resets to 0 after activation and begins building again.</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p><span class="realm-badge realm-chaos">Chaos</span> realm teams generate Silver Key faster than other realms, making Key Orders a central part of Chaos strategy. See <a href="./../realms/chaos.html">Chaos Realm</a>.</p></div><h2 id="key-order-effects" tabindex="-1">Key Order Effects <a class="header-anchor" href="#key-order-effects" aria-label="Permalink to &quot;Key Order Effects&quot;">​</a></h2><p>Key Orders provide a wide range of effects:</p><table tabindex="0"><thead><tr><th>Effect Category</th><th>Examples</th></tr></thead><tbody><tr><td>Damage</td><td>Deal massive damage to all enemies</td></tr><tr><td>Healing</td><td>Restore HP to the entire team</td></tr><tr><td>Buffs</td><td>Grant team-wide ATK, DEF, or special buffs</td></tr><tr><td>Utility</td><td>Draw cards, gain Arithmetica, generate Madness Points</td></tr></tbody></table><h2 id="choosing-a-key-order" tabindex="-1">Choosing a Key Order <a class="header-anchor" href="#choosing-a-key-order" aria-label="Permalink to &quot;Choosing a Key Order&quot;">​</a></h2><ul><li><strong>DPS teams</strong> -- Equip a damage-focused Key Order for burst windows.</li><li><strong>Survival content</strong> -- Equip a healing or defensive Key Order.</li><li><strong>Chaos teams</strong> -- Key Orders are your primary win condition; invest in the strongest one available.</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Key Orders take time to charge. In short fights, you may never reach 1000 Silver Key. For quick battles, other strategies may be more effective.</p></div><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./list.html">Key Orders List</a></li><li><a href="./../modes/combat.html">Combat System</a></li><li><a href="./../realms/chaos.html">Chaos Realm</a></li></ul>',15)])])}const g=t(o,[["render",i]]);export{y as __pageData,g as default};
